async (params, browser) => {
  // Open Gmail
  await browser.open('https://mail.google.com/mail/u/0/#inbox')

  // Wait for Gmail to load
  await browser.waitForSelector('input[aria-label=\'Search mail\']', 15000)

  // Let Gmail fully initialize
  await browser.wait(2000)

  // Enter search query and submit
  const execute_search = await browser.evaluate(`const searchInput = document.querySelector('input[aria-label="Search mail"]'); if (searchInput) { searchInput.focus(); searchInput.click(); await new Promise(r => setTimeout(r, 300)); searchInput.select(); document.execCommand('insertText', false, params.query); await new Promise(r => setTimeout(r, 300)); searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter', code: 'Enter', keyCode: 13, which: 13, bubbles: true })); } return { searched: true }`)

  // Wait for search results
  await browser.wait(3000)

  // Scrape search results
  const search_results = await browser.evaluate(`const rows = document.querySelectorAll('tr.zA'); const results = []; for (let i = 0; i < Math.min(rows.length, 25); i++) { const row = rows[i]; const senderEl = row.querySelector('.yX .yW span[email], .zF'); const subjectEl = row.querySelector('.bog span, .y6 span'); const previewEl = row.querySelector('.y2'); const dateEl = row.querySelector('.xW span[title], .xW span'); const isUnread = row.classList.contains('zE'); const starEl = row.querySelector('.T-KT'); const isStarred = starEl ? starEl.classList.contains('T-KT-Jp') : false; results.push({ sender: senderEl ? (senderEl.getAttribute('email') || senderEl.getAttribute('name') || senderEl.textContent.trim()) : '', subject: subjectEl ? subjectEl.textContent.trim() : '', preview: previewEl ? previewEl.textContent.trim().replace(/^\s*-\s*/, '') : '', date: dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : '', unread: isUnread, starred: isStarred }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
